(()=>{"use strict";!function(){const t=document.querySelectorAll('.toggle input[type="checkbox"], .toggle input[type="radio"]');for(const e of t){const o=e.parentElement,i=navigator.userAgent;(/iPad|iPhone|iPod/.test(i)||"MacIntel"===navigator.platform&&navigator.maxTouchPoints>1)&&o.setAttribute("tabindex","-1"),t&&e.addEventListener("click",(()=>{o.classList.remove("toggle--ripple"),o.classList.add("toggle--ripple")}))}}()})();